# Python implementation of a file summarizer agent
import anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "read_file",
        "description": "Read the contents of a file by path.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Absolute file path"}
            },
            "required": ["path"]
        }
    }
]

def read_file(path: str) -> str:
    try:
        with open(path) as f:
            return f.read()
    except FileNotFoundError:
        return f"Error: file not found at {path}"

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})
        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if b.type == "text")
        # dispatch tool calls
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = read_file(**block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })
        messages.append({"role": "user", "content": tool_results})

print(run_agent("Summarize the file at /etc/hosts"))

// TypeScript implementation of the same agent
import Anthropic from "@anthropic-ai/sdk";
import { readFileSync } from "fs";

const client = new Anthropic();

const tools: Anthropic.Tool[] = [
  {
    name: "read_file",
    description: "Read the contents of a file by path.",
    input_schema: {
      type: "object" as const,
      properties: {
        path: { type: "string", description: "Absolute file path" }
      },
      required: ["path"]
    }
  }
];

function readFile(path: string): string {
  try {
    return readFileSync(path, "utf-8");
  } catch {
    return `Error: file not found at ${path}`;
  }
}

async function runAgent(userMessage: string): Promise<string> {
  const messages: Anthropic.MessageParam[] = [
    { role: "user", content: userMessage }
  ];
  while (true) {
    const response = await client.messages.create({
      model: "claude-sonnet-4-5",
      max_tokens: 2048,
      tools,
      messages,
    });
    messages.push({ role: "assistant", content: response.content });
    if (response.stop_reason === "end_turn") {
      const textBlock = response.content.find(b => b.type === "text");
      return textBlock?.type === "text" ? textBlock.text : "";
    }
    const toolResults: Anthropic.ToolResultBlockParam[] = response.content
      .filter(b => b.type === "tool_use")
      .map(b => {
        if (b.type !== "tool_use") return null!;
        const result = readFile((b.input as { path: string }).path);
        return { type: "tool_result" as const, tool_use_id: b.id, content: result };
      });
    messages.push({ role: "user", content: toolResults });
  }
}

runAgent("Summarize the file at /etc/hosts").then(console.log);
